from flask import Flask, request, jsonify
import os
import json
import time
from threading import Lock

app = Flask(__name__)
cache_lock = Lock()
cache_file = 'cache.json'
cache_expiration = 300  # seconds

def load_cache():
    if os.path.exists(cache_file):
        with open(cache_file, 'r') as f:
            return json.load(f)
    return {}

def save_cache(cache):
    with open(cache_file, 'w') as f:
        json.dump(cache, f)

cache = load_cache()

def is_cache_valid(timestamp):
    return time.time() - timestamp < cache_expiration

@app.route('/api/data', methods=['GET'])
def get_data():
    key = request.args.get('key')
    if not key:
        return jsonify({'error': 'Key parameter is required'}), 400

    with cache_lock:
        if key in cache and is_cache_valid(cache[key]['timestamp']):
            return jsonify(cache[key]['data'])

        # Simulate expensive API call
        response_data = {'data': f'Expensive data for {key}', 'meta': {'info': 'some metadata'}}
        
        cache[key] = {'data': response_data, 'timestamp': time.time()}
        save_cache(cache)

    return jsonify(response_data)

@app.route('/api/cache', methods=['DELETE'])
def clear_cache():
    global cache
    with cache_lock:
        cache = {}
        save_cache(cache)
    return jsonify({'message': 'Cache cleared'}), 200

if __name__ == '__main__':
    app.run(debug=True)